182	>
183	static __forceinline__ __device__ void store_o(
184	    Tensor0 &rO,	// ((2, 2, 32), 1, 1)
185	    Tensor1 &gOorAccum,	// (BLOCK_SIZE_M, HEAD_DIM_V)
186	    Tensor2 &sOutputBuf,
187	    Tensor3 &sOutputAccumBuf,
188	    SharedMemoryPlan &plan,
189	    float o_scales[2],
