191	    int batch_idx,
192	    int s_q_idx,
193	    int head_block_idx,
194	    int num_valid_seq_q,
195	    int warpgroup_idx,
196	    int idx_in_warpgroup
197	) {
198	    using cutlass::arch::NamedBarrier;
199	    if constexpr (IS_NO_SPLIT) {
200	        // Should convert the output to bfloat16 / float16, and save it to O
201	        // Here we don't pipeline STSM and tma store because it's slower
202	        Tensor sMyOutputBuf = local_tile(sOutputBuf, Shape<_64, _256>{}, make_coord(_0{}, warpgroup_idx));
203	
204	        // Calculate "base" ptrs in advance
205	        // Each STSM fills a chunk of shape 16x16, while we are using SW-OBUF_SW, so we need OBUF_SW/16 base pointers
206	        constexpr int NUM_CHUNKS_IN_SW_ATOM = OBUF_SW/16;
207	        bf16* base_output_buf_ptrs[NUM_CHUNKS_IN_SW_ATOM];
208	        CUTE_UNROLL
209	        for (int i = 0; i < NUM_CHUNKS_IN_SW_ATOM; ++i) {
210	            base_output_buf_ptrs[i] = &sMyOutputBuf((idx_in_warpgroup/32)*16+idx_in_warpgroup%16, idx_in_warpgroup%32/16*8 + i*16);
211	        }
212	
213	        CUTE_UNROLL
214	        for (int idx = 0; idx < (HEAD_DIM_V/2)/16; idx += 1) {
215	            // In each iteration we deal with a chunk of shape 16x16
216	            using bf16x2 = __nv_bfloat162;
217	            bf16x2 a01 = __float22bfloat162_rn(float2{rO(idx*8+0)*o_scales[0], rO(idx*8+1)*o_scales[0]});
218	            bf16x2 a23 = __float22bfloat162_rn(float2{rO(idx*8+2)*o_scales[1], rO(idx*8+3)*o_scales[1]});
219	            bf16x2 a45 = __float22bfloat162_rn(float2{rO(idx*8+4)*o_scales[0], rO(idx*8+5)*o_scales[0]});
220	            bf16x2 a67 = __float22bfloat162_rn(float2{rO(idx*8+6)*o_scales[1], rO(idx*8+7)*o_scales[1]});
221	            SM90_U32x4_STSM_N::copy(
222	                *reinterpret_cast<uint32_t*>(&a01),
223	                *reinterpret_cast<uint32_t*>(&a23),
224	                *reinterpret_cast<uint32_t*>(&a45),
225	                *reinterpret_cast<uint32_t*>(&a67),
226	                *reinterpret_cast<uint128_t*>(base_output_buf_ptrs[idx%4] + (idx/4*4)*16*64)
227	            );
228	        }
229	
230	        cutlass::arch::fence_view_async_shared();
231	        NamedBarrier::arrive_and_wait(256, NamedBarriers::epilogue_r2s_ready);
232	
233	        if (threadIdx.x == 0) {
234	            SM90_TMA_STORE_5D::copy(
235	                &tma_params.tensor_map_o,
236	                plan.u.oBuf.data(),
237	                0, head_block_idx*64, 0,
238	                s_q_idx, batch_idx
239	            );
240	            cute::tma_store_arrive();
241	        }
242	    } else {
243	        // Should save the result to OAccum
244	        CUTLASS_PRAGMA_UNROLL
245	        for (int idx = 0; idx < size(rO); idx += 2) {
246	            int row = (idx_in_warpgroup/32)*16 + (idx_in_warpgroup%32/4) + (idx%4 >= 2 ? 8 : 0);
247	            int col = warpgroup_idx*256 + (idx_in_warpgroup%4)*2 + idx/4*8;
248	            *(float2*)(&(sOutputAccumBuf(row, col))) = float2 {
249	                rO(idx) * o_scales[idx%4>=2],
250	                rO(idx+1) * o_scales[idx%4>=2],
251	            };
252	        }
253	        cutlass::arch::fence_view_async_shared();
254	        
255	        NamedBarrier::arrive_and_wait(256, NamedBarriers::epilogue_r2s_ready);
256	        
257	        if (elect_one_sync()) {
258	            CUTLASS_PRAGMA_UNROLL
259	            for (int local_row = 0; local_row < BLOCK_M / (256/32); ++local_row) {
260	                int row = local_row * (256/32) + (threadIdx.x / 32);
261	                if (row < num_valid_seq_q) {
262	                    SM90_BULK_COPY_S2G::copy(&sOutputAccumBuf(row, _0{}), &gOorAccum(row, _0{}), HEAD_DIM_V*sizeof(float));
263	                }
264	            }
265	            cute::tma_store_arrive();
266	        }
267	    }
268	}
